1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_THRESHOLD = 5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const BLOCK_OF_3_BASE_PREMIUM = 60;
7	const LOYALTY_THRESHOLD_YEARS = 2;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
10	const DEDUCTIBLE = 100;
11	const CAP_MULTIPLIER = 2;
12	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
13	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
14	
15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const INSURANCE_VALUE: Record<string, number> = {
25	  sword: 1000,
26	  amulet: 600,
27	  staff: 800,
28	  potion: 400,
29	  rune: 250,
30	  moonstone: 250,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	
35	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
36	type QuoteStep = { op: "quote"; items: Item[] };
37	type Damage = { itemType: string; amount: number };
38	type Incident = { cause: string; damages: Damage[] };
39	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
40	type Step = QuoteStep | ClaimStep;
41	type Customer = { yearsWithMHPCO: number };
42	type Scenario = { customer: Customer; steps: Step[] };
43	type QuoteResult = { premium: number };
44	type ClaimResult = { payout: number; remainingCap: number };
45	type StepResult = QuoteResult | ClaimResult;
46	
47	type Policy = { items: Item[]; insuranceSum: number; cap: number; capRemaining: number };
48	
49	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
50	
51	const itemSurcharges = (item: Item): number => {
52	  const base = BASE_PREMIUM[item.type];
53	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
54	  const highEnchSurcharge =
55	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
56	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
57	      : 0;
58	  return curseSurcharge + highEnchSurcharge;
59	};
60	
61	const countByType = (items: Item[]): Map<string, number> => {
62	  const counts = new Map<string, number>();
63	  for (const item of items) {
64	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
65	  }
66	  return counts;
67	};
68	
69	const componentGroupBase = (type: string, count: number): number =>
70	  count === 3 ? BLOCK_OF_3_BASE_PREMIUM : count * BASE_PREMIUM[type];
71	
72	const policyBase = (items: Item[]): number => {
73	  const components = items.filter(isComponent);
74	  const mainItems = items.filter((item) => !isComponent(item));
75	  const mainBase = mainItems.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
76	  const componentBase = Array.from(countByType(components)).reduce(
77	    (sum, [type, count]) => sum + componentGroupBase(type, count),
78	    0,
79	  );
80	  return mainBase + componentBase;
81	};
82	
83	const sumItemSurcharges = (items: Item[]): number =>
84	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
85	
86	const loyaltyDiscount = (customer: Customer, base: number): number =>
87	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
88	
89	const followUpDiscount = (isFollowUp: boolean, base: number): number =>
90	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
91	
92	const totalDiscounts = (customer: Customer, isFollowUp: boolean, base: number): number =>
93	  loyaltyDiscount(customer, base) + followUpDiscount(isFollowUp, base);
94	
95	const isKnownItemType = (type: string): boolean => BASE_PREMIUM[type] !== undefined;
96	
97	const assertKnownItemTypes = (items: Item[]): void => {
98	  const unknown = items.find((item) => !isKnownItemType(item.type));
99	  if (unknown) {
100	    throw new Error(`unknown item type: ${unknown.type}`);
101	  }
102	};
103	
104	const quoteStep = (step: QuoteStep, customer: Customer, isFollowUp: boolean): QuoteResult => {
105	  assertKnownItemTypes(step.items);
106	  const base = policyBase(step.items);
107	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
108	  const premium =
109	    base +
110	    firstInsurance +
111	    sumItemSurcharges(step.items) -
112	    totalDiscounts(customer, isFollowUp, base) +
113	    PROCESSING_FEE;
114	  return { premium: Math.ceil(premium) };
115	};
116	
117	const insuranceSum = (items: Item[]): number =>
118	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
119	
120	const makePolicy = (items: Item[]): Policy => {
121	  const sum = insuranceSum(items);
122	  const cap = sum * CAP_MULTIPLIER;
123	  return { items, insuranceSum: sum, cap, capRemaining: cap };
124	};
125	
126	const isHighEnchantmentClaim = (item: Item): boolean =>
127	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
128	
129	const reducedDamage = (amount: number, item: Item): number =>
130	  isHighEnchantmentClaim(item) ? amount * HIGH_ENCHANTMENT_CLAIM_RATE : amount;
131	
132	const findInsuredItem = (policy: Policy, itemType: string): Item => {
133	  const item = policy.items.find((i) => i.type === itemType);
134	  if (!item) {
135	    throw new Error(`damage references item not in policy: ${itemType}`);
136	  }
137	  return item;
138	};
139	
140	const damagePayout = (damage: Damage, policy: Policy): number => {
141	  if (damage.amount < 0) {
142	    throw new Error(`damage amount must be non-negative: ${damage.amount}`);
143	  }
144	  const item = findInsuredItem(policy, damage.itemType);
145	  return reducedDamage(damage.amount, item) - DEDUCTIBLE;
146	};
147	
148	const totalPayout = (damages: Damage[], policy: Policy): number =>
149	  damages.reduce((sum, d) => sum + damagePayout(d, policy), 0);
150	
151	const claimStep = (step: ClaimStep, policies: Policy[]): ClaimResult => {
152	  const policy = policies[step.policy];
153	  const payout = Math.floor(Math.min(totalPayout(step.incident.damages, policy), policy.capRemaining));
154	  policy.capRemaining -= payout;
155	  return { payout, remainingCap: policy.capRemaining };
156	};
157	
158	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
159	  const policies: Policy[] = [];
160	  const results: StepResult[] = scenario.steps.map((step) => {
161	    if (step.op === "quote") {
162	      const isFollowUp = policies.length > 0;
163	      policies.push(makePolicy(step.items));
164	      return quoteStep(step, scenario.customer, isFollowUp);
165	    }
166	    return claimStep(step, policies);
167	  });
168	  return { results };
169	};
